{"type":"tool_use","id":"call_b132b7029ae14e2eb22bd080","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-e/src/index-builder.ts","content":"import { execFile } from "node:child_process";
import { access, constants, readdir } from "node:fs/promises";
import path from "node:path";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

interface LanguageDetection {
  typescript: boolean;
  golang: boolean;
}

interface BuildResult {
  language: string;
  success: boolean;
  output: string;
  error?: string;
}

const TS_EXTENSIONS = new Set([".ts", ".tsx"]);
const GO_EXTENSIONS = new Set([".go"]);

async function hasTool(name: string): Promise<boolean> {
  try {
    await access(name, constants.X_OK);
    return true;
  } catch {
    return false;
  }
}

async function detectLanguages(projectDir: string): Promise<LanguageDetection> {
  const result: LanguageDetection = { typescript: false, golang: false };
  const dirsToScan = ["src", ".", "pkg", "cmd", "internal"];

  for (const dir of dirsToScan) {
    const fullPath = path.resolve(projectDir, dir);
    try {
      await access(fullPath, constants.R_OK);
      await scanDir(fullPath, result);
    } catch {
      continue;
    }
    if (result.typescript && result.golang) break;
  }

  return result;
}

async function scanDir(dir: string, result: LanguageDetection): Promise<void> {
  const entries = await readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    if (result.typescript && result.golang) return;
    const name = entry.name;
    if (name.startsWith(".") || name === "node_modules" || name === "vendor" || name === "dist") continue;

    if (entry.isDirectory()) {
      await scanDir(path.join(dir, name), result);
    } else {
      const ext = path.extname(name);
      if (TS_EXTENSIONS.has(ext)) result.typescript = true;
      if (GO_EXTENSIONS.has(ext)) result.golang = true;
    }
  }
}

async function initSqliteDb(dbPath: string): Promise<void> {
  const { Database } = await import("better-sqlite3");
  const db = new Database(dbPath);
  db.pragma("journal_mode = WAL");
  db.exec(`
    CREATE TABLE IF NOT EXISTS symbols (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      kind TEXT NOT NULL,
      file TEXT NOT NULL,
      line INTEGER NOT NULL,
      language TEXT NOT NULL,
      definition TEXT
    );
    CREATE INDEX IF NOT EXISTS idx_symbols_name ON symbols(name);
    CREATE INDEX IF NOT EXISTS idx_symbols_file ON symbols(file);
    CREATE INDEX IF NOT EXISTS idx_symbols_kind ON symbols(kind);
  `);
  db.close();
}

async function runScipTypescript(
  projectDir: string,
  dbPath: string
): Promise<BuildResult> {
  const scipTs = "scip-typescript";
  if (!(await hasTool(scipTs))) {
    return {
      language: "typescript",
      success: false,
      output: "",
      error: `scip-typescript not found. Install: npm install -g @sourcegraph/scip-typescript`,
    };
  }

  const indexFile = path.join(projectDir, "index.scip");
  try {
    const { stdout } = await execFileAsync(scipTs, ["index", "--project-name", path.basename(projectDir), "--output", indexFile], {
      cwd: projectDir,
      maxBuffer: 10 * 1024 * 1024,
    });

    await importScipDump(indexFile, dbPath, "typescript");
    return { language: "typescript", success: true, output: stdout };
  } catch (err: unknown) {
    const error = err as { stderr?: string; message?: string };
    return {
      language: "typescript",
      success: false,
      output: "",
      error: error.stderr ?? error.message ?? "unknown error",
    };
  }
}

async function runScipGo(
  projectDir: string,
  dbPath: string
): Promise<BuildResult> {
  const scipGo = "scip-go";
  if (!(await hasTool(scipGo))) {
    return {
      language: "golang",
      success: false,
      output: "",
      error: `scip-go not found. Install: go install github.com/sourcegraph/scip-go/cmd/scip-go@latest`,
    };
  }

  const indexFile = path.join(projectDir, "dump.lsif");
  try {
    const { stdout } = await execFileAsync(scipGo, ["index", "--output", indexFile], {
      cwd: projectDir,
      maxBuffer: 10 * 1024 * 1024,
    });

    await importScipDump(indexFile, dbPath, "golang");
    return { language: "golang", success: true, output: stdout };
  } catch (err: unknown) {
    const error = err as { stderr?: string; message?: string };
    return {
      language: "golang",
      success: false,
      output: "",
      error: error.stderr ?? error.message ?? "unknown error",
    };
  }
}

async function importScipDump(
  dumpPath: string,
  dbPath: string,
  language: string
): Promise<void> {
  const { Database } = await import("better-sqlite3");
  const { readFileSync } = await import("node:fs");
  const db = new Database(dbPath);
  const insert = db.prepare(
    "INSERT INTO symbols (name, kind, file, line, language, definition) VALUES (?, ?, ?, ?, ?, ?)"
  );

  let raw: string;
  try {
    raw = readFileSync(dumpPath, "utf-8");
  } catch {
    db.close();
    return;
  }

  const lines = raw.split("\n");
  const vertices: Map<number, { symbol: string; kind: string }> = new Map();
  const documents: Map<number, { path: string }> = new Map();

  for (const line of lines) {
    if (!line.startsWith("vertex")) continue;
    try {
      const parts = JSON.parse(line.slice(6).trim());
      const id = parts.id;
      const type = parts.type;
      if (type === "symbol") {
        vertices.set(id, { symbol: parts.symbol ?? "", kind: parts.kind ?? "unknown" });
      } else if (type === "document") {
        documents.set(id, { path: parts.relative_path ?? "" });
      }
    } catch {
      continue;
    }
  }

  for (const line of lines) {
    if (!line.startsWith("edge")) continue;
    try {
      const parts = JSON.parse(line.slice(4).trim());
      if (parts.type === "contains" && parts.outV1 && parts.inV) {
        const doc = documents.get(parts.outV1);
        const sym = vertices.get(parts.inV);
        if (doc && sym) {
          insert.run(
            sym.symbol,
            sym.kind,
            doc.path,
            parts.property?.start?.line ?? 0,
            language,
            null
          );
        }
      }
    } catch {
      continue;
    }
  }

  db.close();
}

export interface IndexBuildOptions {
  projectDir: string;
  outputDb?: string;
  languages?: string[];
}

export async function buildIndex(options: IndexBuildOptions): Promise<BuildResult[]> {
  const projectDir = path.resolve(options.projectDir);
  const dbPath = options.outputDb ?? path.join(projectDir, ".fg-index.db");

  try {
    await access(projectDir, constants.R_OK);
  } catch {
    throw new Error(`Project directory not accessible: ${projectDir}`);
  }

  await initSqliteDb(dbPath);

  const detected = await detectLanguages(projectDir);
  const results: BuildResult[] = [];
  const requestedLangs = options.languages;

  const shouldRunTs =
    detected.typescript &&
    (!requestedLangs || requestedLangs.includes("typescript"));
  const shouldRunGo =
    detected.golang &&
    (!requestedLangs || requestedLangs.includes("golang"));

  if (!shouldRunTs && !shouldRunGo) {
    throw new Error(
      `No supported languages detected in ${projectDir}. Supported: typescript, golang`
    );
  }

  if (shouldRunTs) {
    results.push(await runScipTypescript(projectDir, dbPath));
  }
  if (shouldRunGo) {
    results.push(await runScipGo(projectDir, dbPath));
  }

  return results;
}

export { detectLanguages };
