import path from "node:path";
import { buildIndex, detectLanguages } from "../index-builder";

function printUsage(): void {
  process.stdout.write(`Usage: fg-index --project-dir <dir> [--output-db <path>] [--languages <lang1>,<lang2>]

Build a code index for a project using SCIP indexers.

Options:
  --project-dir   Path to the project directory (required)
  --output-db     Path for the SQLite database (default: <project-dir>/.fg-index.db)
  --languages     Comma-separated list of languages to index (default: auto-detect)
  --help          Show this help message

Supported languages: typescript, golang

Examples:
  fg-index --project-dir ./my-ts-project
  fg-index --project-dir ./monorepo --languages typescript,golang
  fg-index --project-dir ./api --output-db ./custom-index.db
`);
}

function parseArgs(argv: string[]): Record<string, string | string[] | undefined> {
  const args: Record<string, string | string[] | undefined> = {};
  let i = 2;
  while (i < argv.length) {
    const arg = argv[i];
    if (arg === "--help" || arg === "-h") {
      args["help"] = "true";
      i++;
    } else if (arg === "--project-dir") {
      args["projectDir"] = argv[++i];
      i++;
    } else if (arg === "--output-db") {
      args["outputDb"] = argv[++i];
      i++;
    } else if (arg === "--languages") {
      args["languages"] = argv[++i].split(",");
      i++;
    } else {
      process.stderr.write(`Unknown argument: ${arg}\n`);
      process.exit(1);
    }
  }
  return args;
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv);

  if ("help" in args) {
    printUsage();
    process.exit(0);
  }

  if (!args.projectDir) {
    process.stderr.write("Error: --project-dir is required\n\n");
    printUsage();
    process.exit(1);
  }

  const projectDir = path.resolve(args.projectDir as string);

  process.stdout.write(`Scanning ${projectDir}...\n`);
  const languages = await detectLanguages(projectDir);

  if (languages.typescript) process.stdout.write("  Found: TypeScript\n");
  if (languages.golang) process.stdout.write("  Found: Go\n");

  if (!languages.typescript && !languages.golang) {
    process.stderr.write("No supported languages detected.\n");
    process.exit(1);
  }

  process.stdout.write("Building index...\n");

  try {
    const results = await buildIndex({
      projectDir,
      outputDb: args.outputDb as string | undefined,
      languages: args.languages as string[] | undefined,
    });

    for (const result of results) {
      if (result.success) {
        process.stdout.write(`  ${result.language}: indexed successfully\n`);
      } else {
        process.stderr.write(`  ${result.language}: failed - ${result.error}\n`);
      }
    }

    const allSuccess = results.every((r) => r.success);
    if (allSuccess) {
      process.stdout.write("Index build complete.\n");
    } else {
      process.exit(1);
    }
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    process.stderr.write(`Error: ${message}\n`);
    process.exit(1);
  }
}

main();
